record.field:
{
    "type": "object",
    "properties": {
        "period": {"type": "string", "enum": ["today", "week", "month", "year", "all"], "description": "Period (default: month)"},
        "state": {"type": "string", "enum": ["draft", "sale", "done", "cancel", "all"], "description": "Order state (default: all except cancelled)"},
        "salesperson": {"type": "string", "description": "Filter by salesperson name"}
    }
}

{
    "type": "object",
    "properties": {
        "partner": {"type": "string", "description": "Customer name or ID"},
        "lines": {"type": "array", "items": {"type": "object", "properties": {"product": {"type": "string", "description": "Product name or ID"}, "qty": {"type": "number", "description": "Quantity"}, "price": {"type": "number", "description": "Unit price (optional, uses product price)"}}}, "description": "Order lines"},
        "note": {"type": "string", "description": "Internal note (optional)"}
    },
    "required": ["partner", "lines"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Opportunity name"},
        "partner": {"type": "string", "description": "Contact name or email"},
        "expected_revenue": {"type": "number", "description": "Expected revenue"},
        "description": {"type": "string", "description": "Description/notes"},
        "type": {"type": "string", "enum": ["lead", "opportunity"], "description": "Type (default: opportunity)"}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "task": {"type": "string", "description": "Task name or ID"},
        "hours": {"type": "number", "description": "Worked hours (e.g. 1.5 = 1h30)"},
        "description": {"type": "string", "description": "Work description"},
        "date": {"type": "string", "description": "Date (YYYY-MM-DD, default: today)"}
    },
    "required": ["task", "hours", "description"]
}

{
    "type": "object",
    "properties": {
        "query": {"type": "string", "description": "Name, email, phone or VAT to search"},
        "is_company": {"type": "boolean", "description": "Filter companies only"},
        "customer": {"type": "boolean", "description": "Filter customers only (with sales)"},
        "supplier": {"type": "boolean", "description": "Filter suppliers only"}
    },
    "required": ["query"]
}

{
    "type": "object",
    "properties": {
        "product": {"type": "string", "description": "Product name (partial match)"},
        "low_stock": {"type": "boolean", "description": "Only products below minimum stock"},
        "warehouse": {"type": "string", "description": "Warehouse name"},
        "limit": {"type": "integer", "description": "Result limit (default: 20)"}
    }
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Event title"},
        "start": {"type": "string", "description": "Start datetime (YYYY-MM-DD HH:MM)"},
        "stop": {"type": "string", "description": "End datetime (YYYY-MM-DD HH:MM)"},
        "attendees": {"type": "array", "items": {"type": "string"}, "description": "Attendee names or emails"},
        "description": {"type": "string"}
    },
    "required": ["name", "start", "stop"]
}

{
    "type": "object",
    "properties": {
        "partner": {"type": "string", "description": "Customer/vendor name or ID"},
        "type": {"type": "string", "enum": ["out_invoice", "in_invoice", "out_refund", "in_refund"], "description": "Type (default: out_invoice)"},
        "lines": {"type": "array", "items": {"type": "object", "properties": {"product": {"type": "string"}, "qty": {"type": "number"}, "price": {"type": "number"}, "description": {"type": "string"}}}, "description": "Invoice lines"},
        "ref": {"type": "string", "description": "External reference"}
    },
    "required": ["partner", "lines"]
}

{
    "type": "object",
    "properties": {
        "invoice": {"type": "string", "description": "Invoice number or ID"},
        "amount": {"type": "number", "description": "Amount (default: invoice total)"},
        "journal": {"type": "string", "description": "Payment journal (e.g. Bank, Cash)"}
    },
    "required": ["invoice"]
}

{
    "type": "object",
    "properties": {
        "query": {"type": "string", "description": "Name, reference or barcode"},
        "category": {"type": "string", "description": "Filter by category"},
        "type": {"type": "string", "enum": ["consu", "service", "product"], "description": "Type: consu=consumable, service=service, product=storable"},
        "limit": {"type": "integer", "description": "Limit (default: 10)"}
    },
    "required": ["query"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Expense description"},
        "amount": {"type": "number", "description": "Total amount"},
        "date": {"type": "string", "description": "Date (YYYY-MM-DD, default: today)"},
        "product": {"type": "string", "description": "Expense category/product (e.g. Meal, Transport)"}
    },
    "required": ["name", "amount"]
}

{
    "type": "object",
    "properties": {
        "period": {"type": "string", "enum": ["week", "month", "quarter", "year"], "description": "Period (default: month)"},
        "limit": {"type": "integer", "description": "Top N products (default: 10)"},
        "order_by": {"type": "string", "enum": ["qty", "revenue"], "description": "Order by quantity or revenue (default: revenue)"}
    }
}

{
    "type": "object",
    "properties": {
        "upcoming": {"type": "boolean", "description": "Only upcoming events (default: true)"},
        "name": {"type": "string", "description": "Filter by event name"}
    }
}

{
    "type": "object",
    "properties": {
        "title": {"type": "string", "description": "Report title (appears as header and in file caption)"},
        "html": {"type": "string", "description": "HTML content for the report body. Use h1/h2 for sections, tables for data, div.metric for KPI cards. Do NOT include html/head/body tags - just the content."},
        "filename": {"type": "string", "description": "PDF filename (e.g. sales_report_march.pdf)"}
    },
    "required": ["title", "html"]
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Filter by module name"},
        "state": {"type": "string", "enum": ["installed", "uninstalled", "to upgrade"], "description": "State (default: installed)"},
        "apps_only": {"type": "boolean", "description": "Applications only (default: true)"}
    }
}

{
    "type": "object",
    "properties": {
        "user": {"type": "string", "description": "Filter by user name"},
        "active_today": {"type": "boolean", "description": "Only users who logged in today"}
    }
}
